"use client";

import React, { useEffect, useState } from 'react';
import { FadeIn, StaggerContainer, StaggerItem } from '@/components/animations/MotionUtils';
import { apiClient } from '@/lib/apiClient';
import Link from 'next/link';
import Image from 'next/image';

interface Course {
  id: string;
  title: string;
  slug: string;
  category: string;
  description: string;
  duration: string;
  feeStructure: string | null;
  previewImage?: string;
}

export default function CoursesPage() {
  const [courses, setCourses] = useState<Course[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [activeCategory, setActiveCategory] = useState('All');
  const [hoveredId, setHoveredId] = useState<string | null>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const fetchCourses = async () => {
      try {
        const data = await apiClient.get<Course[]>('/public/courses');
        setCourses(data);
      } catch {
        setError('OFFLINE MODE — SHOWING ARCHIVAL DATA');
        setCourses([
          { id: '1', title: 'CLASS 11 SCIENCE FOUNDATION', slug: 'class-11-science', category: 'Foundation', description: 'Comprehensive 2-year classroom program building strong foundation for Board & Competitive exams.', duration: '2 Years', feeStructure: '₹45,000/YR', previewImage: '/images/courses/class11.png' },
          { id: '2', title: 'TARGET DROPPERS INTENSIVE', slug: 'target-droppers', category: 'Premium', description: 'Intensive 1-year droppers batch focusing exclusively on mastering concepts and problem-solving.', duration: '1 Year', feeStructure: '₹55,000/YR' },
          { id: '3', title: 'CRASH COURSE REVISION', slug: 'crash-course', category: 'Online', description: 'Fast-track revision and massive question banks suitable for the last 3 months of preparation.', duration: '3 Months', feeStructure: '₹12,000' },
          { id: '4', title: 'COMMERCE ELITE PROGRAM', slug: 'commerce-elite', category: 'Commerce', description: 'Specialized CA foundation and board preparation with expert industry mentors.', duration: '2 Years', feeStructure: '₹40,000/YR' },
          { id: '5', title: 'NEET SUPER 30', slug: 'neet-super-30', category: 'Premium', description: 'Targeted medical entrance preparation with daily doubt sessions and AI analytics.', duration: '1 Year', feeStructure: '₹60,000/YR' },
        ]);
      } finally {
        setLoading(false);
      }
    };
    fetchCourses();
  }, []);

  const categories = ['All', ...Array.from(new Set(courses.map((c) => c.category)))];
  const filtered = activeCategory === 'All' ? courses : courses.filter((c) => c.category === activeCategory);

  return (
    <div className="bg-background min-h-screen pb-32">
      
      {/* Editorial Header */}
      <section className="pt-48 pb-32 border-b border-border">
        <div className="max-w-[1800px] mx-auto px-12">
          <div className="flex flex-col items-start leading-[0.85]">
            <FadeIn>
              <span className="font-script text-4xl text-muted-foreground lowercase mb-8 block">exploring</span>
              <h1 className="text-7xl md:text-[10rem] font-black uppercase tracking-tighter-editorial text-foreground">
                Academic <br /> <span className="text-foreground opacity-20">Programs</span>
              </h1>
              <p className="text-xl text-muted-foreground lowercase mt-12 max-w-xl leading-relaxed">
                precisely engineered paths designed to transform potential into peak performance. select your discipline.
              </p>
            </FadeIn>
          </div>
        </div>
      </section>

      {/* Category Filter */}
      <section className="py-12 border-b border-border sticky top-24 bg-background/90 backdrop-blur-md z-30">
        <div className="max-w-[1800px] mx-auto px-12">
          <div className="flex flex-wrap gap-12 items-center">
            <span className="text-[10px] font-bold uppercase tracking-[0.4em] text-muted-foreground opacity-30">Filter by</span>
            {categories.map((cat, i) => (
              <button
                key={i}
                onClick={() => setActiveCategory(cat)}
                className={`text-[12px] font-bold uppercase tracking-[0.2em] transition-all relative py-2 ${
                  activeCategory === cat ? 'text-foreground' : 'text-muted-foreground hover:text-foreground'
                }`}
              >
                {cat}
                {activeCategory === cat && (
                  <div className="absolute bottom-0 left-0 w-full h-px bg-foreground" />
                )}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Editorial List Section */}
      <section className="py-24 relative overflow-hidden">
        {/* Floating Image Container (Magnetic) */}
        <div className="fixed inset-0 pointer-events-none z-50 overflow-hidden">
          {filtered.map((course) => (
             <div 
               key={course.id}
               className={`absolute w-[450px] h-[300px] transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] opacity-0 scale-95 pointer-events-none overflow-hidden border border-border bg-muted ${hoveredId === course.id ? 'opacity-100 scale-100' : ''}`}
               style={{
                 left: typeof window !== 'undefined' ? `${window.innerWidth / 2}px` : '50%',
                 top: typeof window !== 'undefined' ? `${window.innerHeight / 2}px` : '50%',
                 transform: `translate(-50%, -50%) translate(${typeof window !== 'undefined' ? (mousePos.x - window.innerWidth / 2) * 0.1 : 0}px, ${typeof window !== 'undefined' ? (mousePos.y - window.innerHeight / 2) * 0.1 : 0}px)`
               }}
             >
                {course.previewImage ? (
                  <Image 
                    src={course.previewImage} 
                    alt={course.title} 
                    fill 
                    className="object-cover transition-transform duration-700" 
                  />
                ) : (
                  <div className="absolute inset-0 flex items-center justify-center text-[10px] font-bold uppercase tracking-widest text-muted-foreground/20">
                    Course Preview
                  </div>
                )}
                <div className="absolute inset-0 bg-background/20" />
             </div>
          ))}
        </div>

        <div className="max-w-[1800px] mx-auto px-12 relative z-10">
          {error && (
            <div className="mb-24 text-[10px] font-bold uppercase tracking-widest text-[#888888] border border-white/10 p-4 inline-block">
              {error}
            </div>
          )}

          <div className="flex flex-col border-t border-border">
            {filtered.map((course, idx) => (
              <StaggerItem key={course.id} className="w-full">
                <Link 
                  href={`/courses/${course.slug}`}
                  onMouseEnter={() => setHoveredId(course.id)}
                  onMouseLeave={() => setHoveredId(null)}
                  onMouseMove={(e) => setMousePos({ x: e.clientX, y: e.clientY })}
                  className="group flex flex-col md:flex-row items-center py-16 border-b border-border hover:bg-muted/5 transition-colors relative overflow-hidden"
                >
                  {/* Background Massive Index */}
                  <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 text-[15rem] font-black text-foreground opacity-[0.02] pointer-events-none select-none group-hover:opacity-[0.05] transition-opacity duration-700">
                    {course.id.padStart(2, '0')}
                  </div>

                  {/* Left Side: Meta */}
                  <div className="flex flex-col md:w-1/4 mb-8 md:mb-0 relative z-10">
                    <span className="text-[10px] font-bold uppercase tracking-[0.4em] text-muted-foreground opacity-30 mb-2">Category</span>
                    <span className="text-sm font-bold text-foreground group-hover:text-primary transition-colors">{course.category}</span>
                  </div>

                  {/* Center: Title */}
                  <div className="md:w-1/2 flex flex-col items-center text-center md:items-start md:text-left relative z-10">
                    <h2 className="text-5xl md:text-7xl lg:text-8xl font-black uppercase tracking-tighter-editorial text-foreground leading-none group-hover:scale-[1.02] transition-transform duration-700 group-hover:tracking-tight-editorial">
                      {course.title}
                    </h2>
                    <p className="text-sm text-muted-foreground lowercase mt-4 max-w-lg opacity-0 group-hover:opacity-100 transition-opacity duration-700">
                      {course.description}
                    </p>
                  </div>

                  {/* Right Side: Details */}
                  <div className="md:w-1/4 flex flex-col items-center md:items-end text-center md:text-right relative z-10">
                    <div className="flex flex-col mb-4">
                      <span className="text-[10px] font-bold uppercase tracking-[0.4em] text-muted-foreground opacity-30 mb-1">Duration</span>
                      <span className="text-xl font-black text-foreground">{course.duration}</span>
                    </div>
                    {course.feeStructure && (
                      <div className="flex flex-col">
                        <span className="text-[10px] font-bold uppercase tracking-[0.4em] text-muted-foreground opacity-30 mb-1">Investment</span>
                        <span className="text-xl font-black text-foreground">{course.feeStructure}</span>
                      </div>
                    )}
                  </div>

                  {/* Arrow reveal */}
                  <div className="hidden md:flex absolute right-12 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 translate-x-12 group-hover:translate-x-0 transition-all duration-700">
                     <svg width="48" height="48" viewBox="0 0 48 48" fill="none" className="text-foreground">
                        <path d="M12 24H36M36 24L26 14M36 24L26 34" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                     </svg>
                  </div>
                </Link>
              </StaggerItem>
            ))}
          </div>

          {filtered.length === 0 && !loading && (
            <div className="py-48 text-center">
               <span className="font-script text-4xl text-muted-foreground">nothing found</span>
            </div>
          )}
        </div>
      </section>

    </div>
  );
}
